dirs = [(0,1),(0,-1),(1,0),(-1,0)]

def neighbors(r, c, rows, cols):
    for dr, dc in dirs:
        nr, nc = r+dr, c+dc
        if 0 <= nr < rows and 0 <= nc < cols:
            yield nr, nc

